#include <bits/stdc++.h>
using namespace std;

const int N=2e7+10;

int a,m,r;
int b[N],len;
bool flag;

int qpow(int a,int b,int p){
    long long ans=1,base=a%p;
    while(b){
        if(b&1)
            ans=ans*base%p;
        base=base*base%p,b>>=1;
    }
    return ans;
}

int main(){
    scanf("%d%d",&a,&m);
    char ch=getchar();
    while(ch<'0' || '9'<ch) ch=getchar();
    while('0'<=ch && ch<='9') b[++len]=ch-'0',ch=getchar();
    int k=m,t=m;
    for(int i=2;i*i<=t;i++)
        if(t%i==0){
            k=k/i*(i-1);
            while(t%i==0)
                t/=i;
        }
    if(t>1)
    	k=k/t*(t-1);
    for(int i=1;i<=len;i++){
        r=r*10+b[i];
        if(r>=k) flag=true;
        r%=k;
    }
    if(flag)
        printf("%d",qpow(a,r+k,m));
    else
        printf("%d",qpow(a,r,m));
    return 0;
}
